export default async function Posts() {
    const res = await fetch("http://localhost:8080/posts")
    const posts = await res.json()
    return (
        <div>
            <Navigation />
            <h1>Posts</h1>
            <ul>
                {posts.map((post) => (
                    <li key={post.id}>
                        {post.title}
                        {post.description}
                    </li>
                ))}
            </ul>
        </div>
    );
}